1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	};
10	
11	type Item = { type: string };
12	type Step = { items: Item[] };
13	type Scenario = { steps: Step[] };
14	
15	const basePremiumForItems = (items: Item[]): number =>
16	  items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
17	
18	const quotePremium = (items: Item[]): number => {
19	  const policyBase = basePremiumForItems(items);
20	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
21	  return Math.ceil(policyBase + firstInsuranceSurcharge) + PROCESSING_FEE;
22	};
23	
24	export const runScenario = (scenario: Scenario): unknown => {
25	  const results = scenario.steps.map((step) => ({
26	    premium: quotePremium(step.items),
27	  }));
28	  return { results };
29	};
